mapper.select:
SELECT field_name AS name, COUNT(*) AS total_count, SUM(CASE WHEN correct THEN 1 ELSE 0 END) AS correct_count, ROUND(100.0 * SUM(CASE WHEN correct THEN 1 ELSE 0 END) / COUNT(*), 1) AS correct_rate FROM question_attempts
attempted_on >= #{fromDate}
AND import_batch_id = #{importBatchId}
GROUP BY field_name ORDER BY correct_rate DESC, total_count DESC

SELECT minor_name AS name, COUNT(*) AS total_count, SUM(CASE WHEN correct THEN 1 ELSE 0 END) AS correct_count, ROUND(100.0 * SUM(CASE WHEN correct THEN 1 ELSE 0 END) / COUNT(*), 1) AS correct_rate FROM question_attempts
attempted_on >= #{fromDate}
AND import_batch_id = #{importBatchId}
GROUP BY minor_name ORDER BY correct_rate DESC, total_count DESC

SELECT field_name, major_name, minor_name, COUNT(*) AS total_count, SUM(CASE WHEN correct THEN 1 ELSE 0 END) AS correct_count, ROUND(100.0 * SUM(CASE WHEN correct THEN 1 ELSE 0 END) / COUNT(*), 1) AS correct_rate FROM question_attempts
attempted_on >= #{fromDate}
AND import_batch_id = #{importBatchId}
GROUP BY field_name, major_name, minor_name

SELECT minor_name AS name,
       COUNT(*) AS total_count,
       SUM(CASE WHEN correct THEN 1 ELSE 0 END) AS correct_count,
       ROUND(100.0 * SUM(CASE WHEN correct THEN 1 ELSE 0 END) / COUNT(*), 1) AS correct_rate
FROM question_attempts


        attempted_on >= #{fromDate}


        AND import_batch_id = #{importBatchId}


GROUP BY minor_name
ORDER BY correct_rate ASC, total_count DESC
LIMIT #{limit}

SELECT id, attempted_on, correct, field_name, major_name, minor_name,
       source_label, source_url, import_batch_id, created_at
FROM question_attempts


        attempted_on >= #{fromDate}


        AND import_batch_id = #{importBatchId}


ORDER BY attempted_on DESC, id DESC
LIMIT #{limit}
